(12, 'Segédanyagok a tanításhoz\r\n\r\n(tanároknak)', 4, ' Történelemtanárok Túlélőkészlete\r\n\r\n \r\n\r\nTörténelemtanítás\r\n\r\nÚjkor.hu', 'test');
