(13, 'Történelmi források, adatbázisok', 5, 'Adatbázisok Online\r\n\r\n\r\n\r\nFortepan - fotóarchívum\r\n\r\n\r\nAzopan Fotóarchívum\r\n\r\nHungaricana Közgyűjteményi portál - főoldal\r\n\r\n\r\nHungaricana - Képcsarnok\r\n\r\n\r\nHungaricana - Könyv- és Dokumentumtár\r\n\r\n \r\n\r\n\r\n Hungaricana - Térképek és Építészeti Tervek\r\n\r\n\r\nHungaricana - Levéltár\r\n\r\n\r\nHungaricana - Budapest időgép \r\n\r\n\r\nHungaricana - Népzenei Gyűjtemény\r\n\r\n\r\nArcanum térképek\r\n\r\n\r\nPazirik stúdió animációi\r\n\r\n\r\nTörténelmi források elemzése - Sulinet Tudásbázis \r\n\r\n\r\nVárak és erődített helyek a Kárpát-medencében \r\n\r\n\r\nGoogle Arts & Culture - Történelmi események\r\n\r\nGoogle Arts & Culture - Történelmi alakok\r\n\r\nGoogle Arts & Culture - Gyűjtemények\r\n\r\nGoogle Arts & Culture - Művészeti irányzatok\r\n\r\nHistory-maps -Történeti térképek', 'test'),
(14, 'Történelmi folyóiratok, források, érdekességek', 6, '\r\n\r\nBBC History Magazin  \r\n\r\n\r\n\r\nMúlt-kor történelmi magazin\r\n\r\n\r\n\r\nRubicon online\r\n\r\n\r\n\r\nNapi Történelmi Forrás\r\n\r\n\r\nRitkán látható történelem - weboldal', 'test'),
(15, 'Ókori Róma', 1, '<h2>Az ókori Róma</h2>\r\n\r\n<h3>Itália földje</h3>\r\n<ul>\r\n<li>A Földközi-tengerbe hosszan benyúló félsziget.</li>\r\n<li>Északról az Alpok hegyei védik.</li>\r\n<li>Közepén az Appenninek hegyláncai húzódnak.</li>\r\n<li>A partok mentén földművelésre alkalmas dombvidékek vannak.</li>\r\n<li>Éghajlata mediterrán.</li>\r\n</ul>\r\n\r\n<h3>Itália népei</h3>\r\n<ul>\r\n<li>Italicus törzsek (i. e. 2. évezred): latinok, szabinok, szamniszok, umberek.</li>\r\n<li>Etruszkok: i. e. 1. évezredben városokat hoztak létre a nyugati részen.</li>\r\n<li>Görögök: városaik a déli részen épültek a gyarmatosítás korában.</li>\r\n</ul>\r\n\r\n<hr>\r\n\r\n<h2>Róma alapítása</h2>\r\n<ul>\r\n<li>A hagyomány szerint Romulus és Remus alapította i. e. 753-ban.</li>\r\n<li>A 10. században latin és szabin pásztorok telepedtek le a Tiberis melletti hét dombon.</li>\r\n</ul>\r\n\r\n<hr>\r\n\r\n<h2>A római történelem korszakai</h2>\r\n\r\n<h3>A királyság kora</h3>\r\n<ul>\r\n<li>Hét király uralkodott (első: Romulus).</li>\r\n<li>Utolsó három etruszk eredetű → erős etruszk befolyás.</li>\r\n<li>Átvették az etruszk szokásokat: művészet, írás, jóslás, életmód.</li>\r\n</ul>\r\n\r\n<h4>Társadalom</h4>\r\n<ul>\r\n<li>Patríciusok: nemzetségfők, földbirtokosok.</li>\r\n<li>Plebejusok: jognélküli köznép.</li>\r\n</ul>\r\n\r\n<p>\r\nI. e. 510-ben elűzték Tarquinius Superbust → kialakult a respublica (köztársaság).\r\n</p>\r\n\r\n<hr>\r\n\r\n<h3>A köztársaság kora</h3>\r\n\r\n<h4>Államszervezet</h4>\r\n<ul>\r\n<li>Magistratusok:\r\n  <ul>\r\n    <li>Consul</li>\r\n    <li>Praetor</li>\r\n    <li>Quaestor</li>\r\n    <li>Censor</li>\r\n    <li>Aedilis</li>\r\n    <li>Dictator</li>\r\n  </ul>\r\n</li>\r\n<li>Népgyűlés</li>\r\n<li>Szenátus (SPQR)</li>\r\n</ul>\r\n\r\n<h4>Patrícius–plebejus harc</h4>\r\n<ul>\r\n<li>Néptribunus vétójoggal</li>\r\n<li>XII táblás törvények</li>\r\n<li>Adósrabszolgaság eltörlése</li>\r\n<li>Licinius–Sextius földtörvény</li>\r\n<li>Hivatalviselés joga</li>\r\n<li>Házasság engedélyezése</li>\r\n</ul>\r\n\r\n<p>\r\nKialakult a nobilitas (patrícius + gazdag plebejus).\r\n</p>\r\n\r\n<hr>\r\n\r\n<h2>Róma hódításai</h2>\r\n\r\n<h3>Itália meghódítása</h3>\r\n<ul>\r\n<li>Védekező háborúk etruszkok, gallok ellen.</li>\r\n<li>Közép- és Dél-Itália elfoglalása.</li>\r\n<li>Coloniák alapítása.</li>\r\n<li>Divide et impera elv.</li>\r\n</ul>\r\n\r\n<h3>Pun háborúk</h3>\r\n\r\n<h4>I. pun háború (i. e. 264–241)</h4>\r\n<ul>\r\n<li>Szicília birtoklása.</li>\r\n<li>Corvus alkalmazása.</li>\r\n<li>83 tonna ezüst sarc.</li>\r\n</ul>\r\n\r\n<h4>II. pun háború (i. e. 218–201)</h4>\r\n<ul>\r\n<li>Hannibal átkel az Alpokon.</li>\r\n<li>Cannae (i. e. 216).</li>\r\n<li>Zama (i. e. 202).</li>\r\n<li>3200 tonna ezüst jóvátétel.</li>\r\n</ul>\r\n\r\n<h4>III. pun háború (i. e. 149–146)</h4>\r\n<ul>\r\n<li>Karthágó lerombolása.</li>\r\n</ul>\r\n\r\n<h3>Hellenisztikus Kelet</h3>\r\n<ul>\r\n<li>Makedónia legyőzése (i. e. 168).</li>\r\n<li>Görög poliszok leigázása (i. e. 146).</li>\r\n<li>Mare nostrum.</li>\r\n</ul>\r\n\r\n<hr>\r\n\r\n<h2>A köztársaság válsága</h2>\r\n\r\n<h3>Okai</h3>\r\n<ul>\r\n<li>Földkérdés (ager publicus).</li>\r\n<li>Hadsereg problémája.</li>\r\n<li>Rabszolgafelkelések.</li>\r\n<li>Államirányítás zavarai.</li>\r\n</ul>\r\n\r\n<h3>Gracchusok</h3>\r\n<ul>\r\n<li>Tiberius (i. e. 133) – földreform.</li>\r\n<li>Caius (i. e. 123) – polgárjog, provinciák reformja.</li>\r\n</ul>\r\n\r\n<h3>Polgárháborúk</h3>\r\n<ul>\r\n<li>Néppárt (populares).</li>\r\n<li>Szenátori párt (optimates).</li>\r\n</ul>\r\n\r\n<h3>Marius reformjai</h3>\r\n<ul>\r\n<li>Zsoldoshadsereg.</li>\r\n<li>Veterán földosztás.</li>\r\n</ul>\r\n\r\n<h3>Sulla diktatúrája</h3>\r\n<ul>\r\n<li>Proscriptio.</li>\r\n<li>Szenátus létszámának növelése.</li>\r\n</ul>\r\n\r\n<h3>Spartacus (i. e. 74–71)</h3>\r\n<ul>\r\n<li>Felkelés Capuában.</li>\r\n<li>Keresztre feszítések.</li>\r\n</ul>\r\n\r\n<h3>Első triumvirátus</h3>\r\n<ul>\r\n<li>Caesar</li>\r\n<li>Crassus</li>\r\n<li>Pompeius</li>\r\n</ul>\r\n\r\n<h3>Caesar egyeduralma</h3>\r\n<ul>\r\n<li>Pharsalos (i. e. 48).</li>\r\n<li>Naptárreform.</li>\r\n<li>Meggyilkolása (i. e. 44).</li>\r\n</ul>\r\n\r\n<h3>Második triumvirátus</h3>\r\n<ul>\r\n<li>Octavianus</li>\r\n<li>Antonius</li>\r\n<li>Lepidus</li>\r\n<li>Actium (i. e. 31).</li>\r\n</ul>\r\n\r\n<hr>\r\n\r\n<h2>Augustus és a császárság</h2>\r\n\r\n<ul>\r\n<li>Augustus (i. e. 27 – i. u. 14).</li>\r\n<li>Princeps.</li>\r\n<li>Pax Romana.</li>\r\n<li>Természetes határok (Rajna–Duna).</li>\r\n</ul>\r\n\r\n<hr>\r\n\r\n<h2>A császárság kora</h2>\r\n\r\n<h3>Julius–Claudius dinasztia</h3>\r\n<ul>\r\n<li>Tiberius</li>\r\n<li>Caligula</li>\r\n<li>Claudius</li>\r\n<li>Nero</li>\r\n</ul>\r\n\r\n<h3>Flaviusok</h3>\r\n<ul>\r\n<li>Vespasianus</li>\r\n<li>Titus (Colosseum, Vezúv)</li>\r\n<li>Domitianus</li>\r\n</ul>\r\n\r\n<h3>Antoniusok</h3>\r\n<ul>\r\n<li>Nerva</li>\r\n<li>Traianus</li>\r\n<li>Hadrianus (Limes)</li>\r\n<li>Antoninus Pius</li>\r\n<li>Marcus Aurelius</li>\r\n<li>Lucius Verus</li>\r\n<li>Commodus</li>\r\n</ul>\r\n\r\n<hr>\r\n\r\n<h2>A 3. század válsága</h2>\r\n<ul>\r\n<li>Kétfrontos háborúk.</li>\r\n<li>Colonus rendszer.</li>\r\n<li>Gazdasági hanyatlás.</li>\r\n<li>Belviszályok.</li>\r\n</ul>\r\n\r\n<h3>Severusok</h3>\r\n<ul>\r\n<li>Septimius Severus</li>\r\n<li>Caracalla (212: polgárjog)</li>\r\n</ul>\r\n\r\n<h3>Katonacsászárok</h3>\r\n<ul>\r\n<li>Aurelianus</li>\r\n</ul>\r\n\r\n<hr>\r\n\r\n<h2>Dominatus</h2>\r\n\r\n<h3>Diocletianus</h3>\r\n<ul>\r\n<li>Tetrarchia</li>\r\n<li>Adóreform</li>\r\n<li>Közigazgatási reform</li>\r\n</ul>\r\n\r\n<h3>Constantinus</h3>\r\n<ul>\r\n<li>Constantinapolis</li>\r\n<li>Milánói ediktum (313)</li>\r\n<li>Niceai zsinat (325)</li>\r\n</ul>\r\n\r\n<hr>\r\n\r\n<h2>A birodalom bukása</h2>\r\n\r\n<ul>\r\n<li>395: kettészakadás.</li>\r\n<li>410: Alarich feldúlja Rómát.</li>\r\n<li>451: Catalaunum.</li>\r\n<li>455: vandál pusztítás.</li>\r\n<li>476: Romulus Augustulus trónfosztása (Odoaker).</li>\r\n</ul>\r\n\r\n<hr>\r\n\r\n<h2>Pannónia a római korban</h2>\r\n\r\n<h3>Meghódítása</h3>\r\n<ul>\r\n<li>Augustus (i. e. 12–9).</li>\r\n<li>Központ: Aquincum.</li>\r\n<li>Fontos városok: Gorsium, Savaria, Arrabona, Scarabantia, Sopianae.</li>\r\n</ul>\r\n\r\n<h3>Élet a provinciában</h3>\r\n<ul>\r\n<li>Fürdők, amfiteátrumok.</li>\r\n<li>Colóniák.</li>\r\n<li>Kereszténység terjedése.</li>\r\n</ul>\r\n\r\n<h3>Gazdaság</h3>\r\n<ul>\r\n<li>Szőlőművelés.</li>\r\n<li>Vas- és ezüstbányászat.</li>\r\n<li>Kereskedelem.</li>\r\n</ul>\r\n\r\n<p>\r\nAz 5. században a hunok megjelenése a római uralom végét jelentette Pannóniában.\r\n</p>', 'Egyetemestortenelem/okoriroma.png'),
(16, 'A kereszténység születése', 1, '<h2>A kereszténység születése és tanításai</h2>\r\n\r\n<hr>\r\n\r\n<h2>A kereszténység kialakulása</h2>\r\n\r\n<h3>A vallási élet változása a Római Birodalomban</h3>\r\n\r\n<ul>\r\n<li>A görög–római vallás nem követelt meg hitet.</li>\r\n<li>A lényeg a szertartásokon való részvétel volt (szoros kapcsolat az állammal).</li>\r\n<li>Nem nyújtott vigaszt és nem ígért biztonságot.</li>\r\n<li>Ezért egyre többen fordultak a keleti kultuszok felé:</li>\r\n</ul>\r\n\r\n<ul>\r\n<li>Misztériumvallások (Mithrász, Ízisz, Dionüszosz).</li>\r\n<li>Császárok istenítése (különösen a keleti tartományokban).</li>\r\n</ul>\r\n\r\n<h3>Palesztina Jézus korában</h3>\r\n\r\n<ul>\r\n<li>A zsidók egyistenhívő nép voltak.</li>\r\n<li>Várták a Megváltót (Messiás).</li>\r\n<li>A hagyomány őrzői a farizeusok (zsidó írástudók).</li>\r\n<li>Az esszénusok közössége (Kumrán-hegység).</li>\r\n<li>Őskeresztény gyülekezet.</li>\r\n<li>A Megváltó eljövetelét és a bűnbánatot hirdették.</li>\r\n</ul>\r\n\r\n<h3>Jézus Krisztus</h3>\r\n\r\n<p><strong>Elnevezései:</strong></p>\r\n\r\n<ul>\r\n<li>Názáreti Jézus</li>\r\n<li>Jézus = Józsua</li>\r\n<li>Megváltó = Messiás (héber: felszabadító)</li>\r\n<li>Krisztus = Krisztosz (görög)</li>\r\n</ul>\r\n\r\n<p>\r\nÉletét és tanításait az evangéliumok (örömhír) beszélik el az Újszövetségben:\r\nMáté, Márk, Lukács, János.\r\n</p>\r\n\r\n<ul>\r\n<li>Élete utolsó 3 évében tanított.</li>\r\n<li>Új alapokra helyezte a zsidó hitet.</li>\r\n<li>Isten egyetemes, nem csak a zsidó nép istene.</li>\r\n<li>Ezért halálra ítélték.</li>\r\n<li>Tanítványaival, az apostolokkal járta Júdea városait.</li>\r\n<li>Hirdette a végítéletet, a megbocsátást és az üdvösség reményét.</li>\r\n<li>Csak az Istenbe vetett hit és az egymás iránti szeretet számít.</li>\r\n<li>Ostorozta a vagyonszerzést, a kapzsiságot, a gyűlöletet és az erőszakot.</li>\r\n</ul>\r\n\r\n<hr>\r\n\r\n<h2>A keresztény egyház kialakulása</h2>\r\n\r\n<h3>Jézus tanításainak terjedése</h3>\r\n\r\n<p>\r\nJézus tanításai a Római Birodalom széles tömegeire hatottak.\r\n</p>\r\n\r\n<h3>Szent Pál (Saulus) tanítása</h3>\r\n\r\n<ul>\r\n<li>Jézus halálával minden ember bűneit megváltotta.</li>\r\n<li>Tanítása minden népet megszólított.</li>\r\n<li>Mindenki egyenlőnek számított (a rabszolgák is).</li>\r\n<li>Minden keresztény vagyonának és jövedelmének egy részét a közös kasszába adta.</li>\r\n<li>Összejöveteleiket vasárnap tartották.</li>\r\n<li>A szertartást pap vagy püspök vezette.</li>\r\n</ul>\r\n\r\n<h3>A keresztény dogmák kialakulása</h3>\r\n\r\n<ul>\r\n<li>Jézus Krisztus Isten egyszülött fia, a Messiás.</li>\r\n<li>Egyszerre valóságos ember és Isten.</li>\r\n<li>Szentháromság tana: Isten egylényegű három személy:\r\n  <ul>\r\n    <li>Atya</li>\r\n    <li>Fiú</li>\r\n    <li>Szentlélek</li>\r\n  </ul>\r\n</li>\r\n<li>Szűz Mária = Istenanya (Jézus anyja).</li>\r\n<li>Jézust keresztre feszítették és feltámadt.</li>\r\n</ul>\r\n\r\n<h3>Korai egyházszervezet</h3>\r\n\r\n<ul>\r\n<li>Állandó szertartásrend alakult ki.</li>\r\n<li>Ünnepek.</li>\r\n<li>Áldozás.</li>\r\n<li>Keresztelés.</li>\r\n<li>Úrvacsora.</li>\r\n</ul>\r\n\r\n<p><strong>Az egyház tisztségviselői:</strong></p>\r\n\r\n<ul>\r\n<li>Püspökök (episzkoposz = felügyelő).</li>\r\n<li>Presbiterek (idősebbek).</li>\r\n<li>Diakónusok (szolgák).</li>\r\n</ul>\r\n\r\n<hr>\r\n\r\n<h2>A kereszténység győzelme</h2>\r\n\r\n<ul>\r\n<li>Az 1–3. század császárai üldözték a keresztényeket.</li>\r\n<li>Terjedésüket nem tudták megakadályozni.</li>\r\n<li>A 4. század elejétől engedményeket tettek.</li>\r\n</ul>\r\n\r\n<ul>\r\n<li>313: Constantinus milánói ediktuma → engedélyezte a keresztény vallás gyakorlását.</li>\r\n<li>325: niceai zsinat → döntés Jézus egylényegűségéről (Szentháromság tana).</li>\r\n<li>391: Theodosius császár a kereszténységet egyedüli vallássá nyilvánította.</li>\r\n</ul>\r\n\r\n<hr>\r\n\r\n<h2>A keresztény egyházszervezet megszilárdulása</h2>\r\n\r\n<ul>\r\n<li>A 4. században megszilárdult az egyház szervezete.</li>\r\n<li>A közösségeket plébánosok és diakónusok irányították.</li>\r\n<li>Az egyházkerületeket püspökök vezették.</li>\r\n<li>A tartományi központok püspökei metropoliták voltak.</li>\r\n</ul>\r\n\r\n<h3>Az 5 patriarchátus</h3>\r\n\r\n<ul>\r\n<li>Róma</li>\r\n<li>Konstantinápoly</li>\r\n<li>Antiochia</li>\r\n<li>Jeruzsálem</li>\r\n<li>Alexandria</li>\r\n</ul>\r\n\r\n<p>\r\nAz öt patriarchátus élén egymással egyenlő pátriárkák álltak.\r\n</p>', 'Egyetemestortenelem/keresztenysegszul.png'),
(17, 'Vallások az ókorban', 1, '<h2>Vallások az ókorban</h2>\r\n\r\n<p>\r\nAz emberiség legősibb kérdéseinek egyike a világ keletkezése és működése.\r\nAz erre adott válaszok sokfélék lehetnek:\r\n</p>\r\n\r\n<ul>\r\n<li>mitológiai</li>\r\n<li>vallásos</li>\r\n<li>filozófiai</li>\r\n<li>tudományos (ősrobbanás elmélete, evolúció)</li>\r\n</ul>\r\n\r\n<hr>\r\n\r\n<h2>Az ókori Közel-Kelet vallásai</h2>\r\n\r\n<h3>Mezopotámia és Egyiptom</h3>\r\n\r\n<ul>\r\n<li>A mezopotámiai és az egyiptomi vallások népekhez és államokhoz kapcsolódtak.</li>\r\n<li>Politeista (többistenhívő) vallások voltak.</li>\r\n</ul>\r\n\r\n<h4>Mezopotámia</h4>\r\n<ul>\r\n<li>Kezdetben minden város saját hiedelemvilággal rendelkezett.</li>\r\n<li>A papok egységes sumer–akkád–babiloni mitológiát alakítottak ki.</li>\r\n<li>Isteneik ember alakúak voltak.</li>\r\n</ul>\r\n\r\n<h4>Egyiptom</h4>\r\n<ul>\r\n<li>Főisten: Ré (Napisten), akit Amon és Aton néven is tiszteltek.</li>\r\n<li>A fáraók a napisten nevében és védelme alatt uralkodtak.</li>\r\n<li>Isteneik gyakran állati alakot őriztek meg.</li>\r\n<li>Hitük szerint az ember a túlvilágon tovább él.</li>\r\n<li>A testet mumifikálással óvták meg az enyészettől.</li>\r\n</ul>\r\n\r\n<h4>Perzsa vallás</h4>\r\n<ul>\r\n<li>Dualista jellegű (jó és rossz küzdelme).</li>\r\n<li>Alapító: Zarathusztra.</li>\r\n<li>A jó teremtő és a gonosz romboló harca áll a középpontban.</li>\r\n<li>Az ember maga dönti el, melyik oldalra áll.</li>\r\n</ul>\r\n\r\n<h4>A zsidó vallás</h4>\r\n<ul>\r\n<li>Monoteista (egyistenhívő) vallás.</li>\r\n<li>A törzsi istenek közül Jahve tisztelete maradt fenn.</li>\r\n<li>Jahve a világmindenség egyetlen istene lett.</li>\r\n<li>Isten láthatatlan és mindenható.</li>\r\n<li>A babiloni fogság után (Kr. e. 6. század) megszilárdult a monoteizmus.</li>\r\n<li>Tanításaikat a héber Biblia (Ószövetség) foglalja össze.</li>\r\n</ul>\r\n\r\n<hr>\r\n\r\n<h2>Az ókori India és Kína vallásai</h2>\r\n\r\n<h3>India</h3>\r\n\r\n<ul>\r\n<li>Politeista vallások: brahmanizmus és buddhizmus.</li>\r\n<li>A brahmanizmus főistenei: Brahma, Visnu, Siva.</li>\r\n<li>Az újjászületést (reinkarnációt) a karma határozza meg.</li>\r\n<li>A buddhizmus célja a nirvána (a lélek nyugalmi állapota).</li>\r\n</ul>\r\n\r\n<h3>Kína</h3>\r\n\r\n<ul>\r\n<li>Az univerzizmus az ég, föld és ember harmonikus egységét hirdeti.</li>\r\n<li>Jelképe a jin–jang.</li>\r\n<li>Kr. e. 6. században két rendszer alakult ki:\r\n  <ul>\r\n    <li>Taoizmus</li>\r\n    <li>Konfucianizmus</li>\r\n  </ul>\r\n</li>\r\n<li>Konfuciusz (Kung-Fu-ce): erkölcsi nevelés, hagyománytisztelet, közösségi érdek.</li>\r\n<li>Lao-ce: a Tao (a természet törvénye) szerinti élet.</li>\r\n</ul>\r\n\r\n<hr>\r\n\r\n<h2>A görög vallás jellemzői</h2>\r\n\r\n<ul>\r\n<li>Politeista vallás.</li>\r\n<li>A világ és az istenek a káoszból jöttek létre.</li>\r\n<li>Isteneiket ember alakúnak (antropomorf) képzelték el.</li>\r\n<li>Tetteiket a görög mitológia meséli el.</li>\r\n<li>Az istenek több nemzedéke váltotta egymást.</li>\r\n<li>Az olimposzi isteneket az egész görögség tisztelte.</li>\r\n<li>Héroszok (félistenek) is szerepeltek a mítoszokban.</li>\r\n<li>A vallás a közösséghez tartozást fejezte ki.</li>\r\n<li>A templom előtt papok mutattak be áldozatot.</li>\r\n<li>Jóslás: Delphoi és Dodona jósdái.</li>\r\n<li>Ünnepségek és versenyek → színház és olimpia (Kr. e. 776).</li>\r\n<li>Kiemelt szerepük volt a pánhellén kultuszhelyeknek.</li>\r\n<li>A kultikus életből fejlődött ki az építészet és a művészet.</li>\r\n</ul>\r\n\r\n<hr>\r\n\r\n<h2>A római vallás jellemzői</h2>\r\n\r\n<ul>\r\n<li>Kezdetben természeti jelenségeket és ősök szellemét tisztelték.</li>\r\n<li>Az etruszk hatásra megjelentek a görög mintájú istenek.</li>\r\n<li>Az istenek meghatározott feladatkört láttak el.</li>\r\n<li>Akaratukat természeti jelek útján közölték.</li>\r\n<li>A jelek értelmezése a jóspapok feladata volt (pl. madárjós).</li>\r\n<li>Császárkultusz: az uralkodók vallásos tisztelete.</li>\r\n<li>Misztériumvallások keletről érkeztek.</li>\r\n<li>A válság hatására nőtt az istennel való személyes kapcsolat igénye.</li>\r\n<li>Ez elősegítette az új vallások (pl. kereszténység) terjedését.</li>\r\n</ul>\r\n\r\n<hr>\r\n\r\n<h2>A kereszténység kialakulása</h2>\r\n\r\n<h3>A vallási élet változása a Római Birodalomban</h3>\r\n<ul>\r\n<li>A görög–római vallás nem követelt meg hitet.</li>\r\n<li>A szertartásokon való részvétel volt a lényeg.</li>\r\n<li>Nem nyújtott vigaszt és biztonságot.</li>\r\n<li>Keleti kultuszok terjedtek:\r\n  <ul>\r\n    <li>Mithras</li>\r\n    <li>Ízisz</li>\r\n    <li>Dionüszosz</li>\r\n  </ul>\r\n</li>\r\n<li>Császárok istenítése (keleti tartományok).</li>\r\n</ul>\r\n\r\n<h3>Palesztina Jézus korában</h3>\r\n<ul>\r\n<li>A zsidók a Messiást várták.</li>\r\n<li>Farizeusok: írástudók.</li>\r\n<li>Esszénusok (Kumrán).</li>\r\n<li>Őskeresztény gyülekezet.</li>\r\n</ul>\r\n\r\n<h3>Jézus Krisztus</h3>\r\n<ul>\r\n<li>Elnevezései: Názáreti, Józsua, Messiás, Krisztosz.</li>\r\n<li>Tanításait az evangéliumok (Máté, Márk, Lukács, János) őrzik.</li>\r\n<li>Hirdette a megbocsátást és az üdvösséget.</li>\r\n<li>Az Istenbe vetett hit és az egymás iránti szeretet számít.</li>\r\n<li>Halálra ítélték.</li>\r\n</ul>\r\n\r\n<hr>\r\n\r\n<h2>A kereszténység győzelme</h2>\r\n\r\n<ul>\r\n<li>1–3. század: üldözések.</li>\r\n<li>313: milánói ediktum (Constantinus).</li>\r\n<li>325: niceai zsinat.</li>\r\n<li>391: Theodosius államvallássá tette.</li>\r\n</ul>', 'Egyetemestortenelem/vallasokazokorban.png'),
(19, 'Hóditó birodalmak', 1, '<h2>1. A hunok</h2>\r\n\r\n<ul>\r\n<li>A hunok őshazája a Belső-Ázsiában lévő Góbi-sivatagban volt. Nomád vagy félnomád életmódot folytattak, ami főként nagyállattartást jelentett. Élőhelyük elsivatagosodása és túlnépesedésük miatt vándorlásra kényszerültek. Fokozódó támadásaik miatt egyesítették a kínaiak az északi határt védő falrendszert a 3. században (Nagyfal). Emiatt a hunok nyugat felé vándoroltak tovább, ahol maguk előtt tolták a sztyeppéken élő kisebb nomád népeket.</li>\r\n\r\n<li>375 körül Balambér vezetésével átkeltek a Volgán Európába és legyőzték a kelet felé nyomuló gótokat (keleti gótok). A menekülő keleti gótok felgyorsították a különféle pusztai népek erőltetett nyugati irányú vándorlását (népvándorlás). Róma kénytelen volt befogadni a menekülő népeket, akiktől védelmet remélt.</li>\r\n\r\n<li>A behódolt népek a hunok segédnépeivé váltak. Megjelenésük hatására a rómaiak Pannónia elhagyására kényszerültek az 5. század elején. A hunok Ruga, majd Bleda vezetésével a Kárpát-medencébe helyezték birodalmuk központját.</li>\r\n\r\n<li>Attilla (Kr. u. 434–453) vezetésével Konstantinápolyt adófizetésre kényszerítették, majd nyugatnak fordult. Róma a befogadott népekkel összefogva megállította a hun előrenyomulást. (Kr. u. 451 Catalaunum-i csata).</li>\r\n\r\n<li>Attila később Itáliát támadta, de Róma előtt váratlanul visszafordult. Halála után fiai között hatalmi harcok kezdődtek, ezért a Hun Birodalom felbomlott.</li>\r\n\r\n<li>A hun nép maradékai a Balkán-félsziget keleti felére, a Fekete-tenger partvidékére húzódtak vissza (bolgárok földje), ahol beolvadtak az ott élő és oda érkező népek közé.</li>\r\n</ul>\r\n\r\n<h2>2. Frankok és bizánciak</h2>\r\n\r\n<h3>A Nyugat-Római Birodalom utódállamai</h3>\r\n\r\n<ul>\r\n<li><b>Keleti Gót Királyság:</b> Nagy Theodorik vezetésével jött létre az 5. század végén Itáliában.</li>\r\n<li><b>Longobárd Királyság:</b> A 6. század közepén longobárdok alapították Itália északi részén.</li>\r\n<li><b>Pápai Állam:</b> A Róma központú egyház függetlenítette magát a világi hatalomtól. 756-ban jött létre, amikor Kis Pippin Róma és Ravenna vidékét a pápaságnak adományozta.</li>\r\n<li><b>Frank Királyság:</b> A germán frank törzsek az 5. században betelepültek Gallia területére. Klodvig felvette a katolikus kereszténységet és dinasztiát alapított (Meroving dinasztia).</li>\r\n</ul>\r\n\r\n<h3>A Frank Birodalom</h3>\r\n\r\n<ul>\r\n<li>Martell Károly majordomus (udvarnagy) 732-ben Poitiers-nál legyőzte az előrenyomuló arabokat.</li>\r\n<li>Fia, Kis Pippin 751-ben a pápa segítségével királlyá koronáztatta magát (hálából létrehozta a Pápai Államot).</li>\r\n<li>Kis Pippin fia, Nagy Károly: hódításokat folytatott, erős államot szervezett, 800-ban császárrá koronáztatta magát.</li>\r\n<li>A frank állam központja az Aacheni palota volt.</li>\r\n<li>A birodalom területét grófságokra és őrgrófságokra osztották, élükön a grófok (comes) és őrgrófok álltak. Feladatuk: adószedés, bíráskodás, hadvezetés.</li>\r\n<li>Alkuin vezetésével egységesítették az írást (karoling minuscula). Az írásos ügyek intézését a kancellária végezte (oklevelek). Írott rendeletekkel irányították a birodalmat.</li>\r\n<li>Nagy Károly halála után hatalmi harcok kezdődtek.</li>\r\n<li>843-ban a verduni szerződésben unokái három részre osztották a birodalmat:\r\n<ul>\r\n<li>Nyugati frank királyság: Kopasz Károly birtoka lett (Franciaország).</li>\r\n<li>Keleti frank királyság: Német Lajos birtoka lett (Németország).</li>\r\n<li>Középső területek: Lothar birtoka lett (Itália, Burgundia, Lotharingia).</li>\r\n</ul>\r\n</li>\r\n<li>A birodalom gyengeségét kihasználva a tartományok vezetői önállósodtak. Anarchia bontakozott ki, a normann (viking) és arab támadások ellen sokáig képtelenek voltak védekezni.</li>\r\n<li>A külső támadások hatására erős központi hatalom jött létre Franciaországban, Angliában és a Német-Római Birodalomban (I. Ottó hozta létre 962-ben).</li>\r\n</ul>\r\n\r\n<h3>A Kelet-Római (Bizánci) Birodalom</h3>\r\n\r\n<ul>\r\n<li>A Keletrómai Birodalom a 6–10. század között a világ gazdasági, tudományos és művészeti központja volt. Okai:\r\n<ul>\r\n<li>Gazdasági fejlődés: virágzó városok, kézműves réteg, fennmaradt pénzgazdálkodás, fejlődő kereskedelem.</li>\r\n<li>Erős államhatalom: központi hadsereg, adórendszer.</li>\r\n</ul>\r\n</li>\r\n<li>A 6. században Justinianus császár (527–565) célja a Római Birodalom feltámasztása volt:\r\n<ul>\r\n<li>Corpus Juris Civilis (római jog összefoglalása).</li>\r\n<li>Hadjáratok Itáliában.</li>\r\n<li>A Hagia Sophia székesegyház felépítése Konstantinápolyban.</li>\r\n</ul>\r\n</li>\r\n<li>A 8. században arab támadások miatt területvesztés történt. A Makedón-dinasztia alatt a Keletrómai Birodalomból Bizánci Birodalom lett.</li>\r\n</ul>\r\n\r\n<h2>3. Az iszlám vallás és az arab hódítások</h2>\r\n\r\n<h3>Az iszlám vallás kialakulása</h3>\r\n\r\n<ul>\r\n<li>Az Arab-félszigeten nomád arabok (beduinok) éltek. Egymás ellen harcoltak vízért, oázisokért, állatokért. A tömjénút mentén virágzó városok voltak, pl. Mekka, ahol a Kábát őrizték.</li>\r\n<li>Az iszlám kialakulása Mohamed (570–632) fellépésével kezdődött.\r\n<ul>\r\n<li>Allah egyetlen isten.</li>\r\n<li>Gábriel arkangyal közvetítette a kinyilatkoztatást.</li>\r\n<li>Végítélet hite.</li>\r\n<li>Iszlám = teljes meghódolás.</li>\r\n<li>Egység gondolata.</li>\r\n</ul>\r\n</li>\r\n<li>622: hidzsra (Mekkából Medinába), a mohamedán időszámítás kezdete.</li>\r\n</ul>\r\n\r\n<h3>Az iszlám fő tanításai</h3>\r\n\r\n<ul>\r\n<li>Allah az isten, Mohamed a prófétája.</li>\r\n<li>Napi öt ima Mekka irányába.</li>\r\n<li>Alamizsnaosztás.</li>\r\n<li>Ramadán havi böjt.</li>\r\n<li>Mekkai zarándoklat.</li>\r\n<li>Dzsihád (szent háború).</li>\r\n<li>Maximum 4 feleség.</li>\r\n<li>Tilalmak: alkohol és disznóhús tilos.</li>\r\n</ul>\r\n\r\n<h3>Az iszlám terjedése</h3>\r\n\r\n<ul>\r\n<li>A 7–8. századra az arabok elfoglalták Afrikát, Hispániát, a Közel-Keletet és eljutottak Indiáig.</li>\r\n<li>Kereskedelmi utak ellenőrzése, hellenisztikus műveltség továbbvitele, Bizánc meggyengülése.</li>\r\n<li>732-ben Poitiers-nál a frankok, 740-ben Bizánc (görögtűz) állította meg őket.</li>\r\n<li>Síita és szunnita irányzat kialakulása.</li>\r\n<li>Fejlett arab tudomány: csillagászat, kémia (alkímia), matematika (algebra).</li>\r\n<li>Megőrizték az antik műveltséget és közvetítették Európa felé.</li>\r\n</ul>', 'Egyetemestortenelem/hoditobirodalmak.png'),
(20, 'Kora középkor', 1, '<h2>A Nyugat-Római birodalom utódállamai</h2>\r\n\r\n<ul>\r\n  <li><strong>Keleti Gót Királyság:</strong> Nagy Theodorik vezetésével jött létre az 5. század végén Itáliában.</li>\r\n  <li><strong>Longobárd Királyság:</strong> a 6. század közepén longobárdok alapították Itália északi részén.</li>\r\n  <li><strong>Pápai Állam:</strong>\r\n    <ul>\r\n      <li>a Róma központú egyház függetlenítette magát a világi hatalomtól</li>\r\n      <li>756-ban jött létre, amikor Kis Pippin Róma és Ravenna vidékét a pápaságnak adományozta</li>\r\n    </ul>\r\n  </li>\r\n  <li><strong>Frank Királyság:</strong>\r\n    <ul>\r\n      <li>a germán frank törzsek az 5. században betelepültek Gallia területére</li>\r\n      <li>Klodvig felvette a katolikus kereszténységet és dinasztiát alapított (Meroving dinasztia)</li>\r\n    </ul>\r\n  </li>\r\n</ul>\r\n\r\n<h2>A Frank Birodalom</h2>\r\n\r\n<h3>A Karoling-dinasztia felemelkedése</h3>\r\n<ul>\r\n  <li><strong>Martell Károly</strong> majordomus (udvarnagy) 732-ben Poitiers-nál legyőzte az előrenyomuló arabokat.</li>\r\n  <li>Fia, <strong>Kis Pippin</strong> 751-ben a pápa segítségével királlyá koronáztatta magát (hálából létrehozta a Pápai Államot).</li>\r\n  <li>Kis Pippin fia, <strong>Nagy Károly</strong>:\r\n    <ul>\r\n      <li>hódításokat folytatott</li>\r\n      <li>erős államot szervezett</li>\r\n      <li>800-ban császárrá koronáztatta magát</li>\r\n    </ul>\r\n  </li>\r\n</ul>\r\n\r\n<h3>A frank állam</h3>\r\n<ul>\r\n  <li>Központja az Aacheni palota</li>\r\n  <li>A birodalom területét grófságokra és őrgrófságokra osztották:\r\n    <ul>\r\n      <li>élükön a grófok (comes) és őrgrófok álltak</li>\r\n      <li>feladatuk: adószedés, bíráskodás, hadvezetés</li>\r\n    </ul>\r\n  </li>\r\n  <li>Alkuin vezetésével egységesítették az írást (karoling minuscula):\r\n    <ul>\r\n      <li>az írásos ügyek intézését a kancellária végezte (oklevelek)</li>\r\n      <li>írott rendeletekkel irányították a birodalmat</li>\r\n    </ul>\r\n  </li>\r\n  <li>Nagy Károly halála után hatalmi harcok kezdődtek:\r\n    <ul>\r\n      <li>843-ban a verduni szerződésben unokái három részre osztották a birodalmat:\r\n        <ul>\r\n          <li>Nyugati frank királyság: Kopasz Károly birtoka (Franciaország)</li>\r\n          <li>Keleti frank királyság: Német Lajos birtoka (Németország)</li>\r\n          <li>Középső területek: Lothar birtoka (Itália, Burgundia, Lotharingia)</li>\r\n        </ul>\r\n      </li>\r\n      <li>A birodalom gyengeségét kihasználva a tartományok vezetői önállósodtak:\r\n        <ul>\r\n          <li>anarchia bontakozott ki</li>\r\n          <li>a normann (viking) és az arab támadások ellen sokáig képtelenek voltak védekezni</li>\r\n        </ul>\r\n      </li>\r\n    </ul>\r\n  </li>\r\n  <li>A külső támadások hatására erős központi hatalom jött létre:\r\n    <ul>\r\n      <li>Franciaország</li>\r\n      <li>Anglia</li>\r\n      <li>Német-Római Birodalom (I. Ottó hozta létre 962-ben)</li>\r\n    </ul>\r\n  </li>\r\n</ul>\r\n\r\n<h2>A Kelet-Római Birodalom</h2>\r\n<ul>\r\n  <li>A Keletrómai Birodalom a 6-10. század között a világ gazdasági, tudományos és művészeti központja volt:\r\n    <ul>\r\n      <li>Gazdasági fejlődés:\r\n        <ul>\r\n          <li>virágzó városokban nagyszámú kézműves réteg élt</li>\r\n          <li>fennmaradt a pénzgazdálkodás</li>\r\n          <li>fejlődött a kereskedelem</li>\r\n        </ul>\r\n      </li>\r\n      <li>Erős államhatalom:\r\n        <ul>\r\n          <li>központi hadsereg</li>\r\n          <li>adórend</li>\r\n        </ul>\r\n      </li>\r\n    </ul>\r\n  </li>\r\n  <li>6. században <strong>Justinianus császár</strong> (527-565):\r\n    <ul>\r\n      <li>Római jog gyűjteményes összefoglalása (Corpus Juris Civilis)</li>\r\n      <li>Hadjáratokat indított a nyugati területek visszahódításáért (Itália)</li>\r\n      <li>Felépítette a Hagia Sophia székesegyházat Konstantinápolyban</li>\r\n    </ul>\r\n  </li>\r\n  <li>8. században az arabok támadásai miatt területeket vesztett, majd a <strong>Makedón-dinasztia</strong> uralma alatt alakult ki a Bizánci Birodalom.</li>\r\n</ul>\r\n\r\n<h2>A szlávok</h2>\r\n<ul>\r\n  <li>Őshazájuk a Visztula - Dnyeper-folyók közötti terület (Pripjáty mocsarak)</li>\r\n  <li>6. században déli és nyugati irányba vándoroltak:\r\n    <ul>\r\n      <li>túlnépesedés</li>\r\n      <li>germán vándorlások</li>\r\n      <li>Bizánc meggyengülése</li>\r\n    </ul>\r\n  </li>\r\n  <li>Fejlődésük szétvált:\r\n    <ul>\r\n      <li>Nyugati szlávok: morvák, csehek, lengyelek</li>\r\n      <li>Déli szlávok: bolgárok, horvátok, szerbek</li>\r\n      <li>Keleti szlávok: oroszok, ukránok, fehér oroszok</li>\r\n    </ul>\r\n  </li>\r\n</ul>\r\n\r\n<h2>A keresztény egyház helyzete a kora középkorban</h2>\r\n<ul>\r\n  <li>Nyugaton a Róma püspökei (pápa) függetlenedtek a világi hatalomtól (756-ban létrejött a Pápai állam)</li>\r\n  <li>Keleten fennmaradt a császárok egyház feletti hatalma</li>\r\n  <li>Az államalapítással egy időben az új népek felvették a kereszténységet:\r\n    <ul>\r\n      <li>Nyugati: Katolikus (Róma központú, egyetemes)</li>\r\n      <li>Keleti: Ortodox / görögkeleti (bizánci) kereszténység</li>\r\n    </ul>\r\n  </li>\r\n  <li>A térítő munkát szerzetesi közösségek végezték (pl. bencések)</li>\r\n  <li>Nyugati és Keleti egyház közötti ellentétek 1054-ben egyházszakadáshoz (Szkizma) vezettek</li>\r\n</ul>\r\n\r\n<h2>Az iszlám vallás kialakulása</h2>\r\n<ul>\r\n  <li>Arab-félsziget, nomád arabok (beduinok)\r\n    <ul>\r\n      <li>Harcoltak a vízért, oázisokért és állatokért</li>\r\n      <li>Kereskedővárosok a tömjénút mentén, pl. Mekka, ahol a Fekete Követ (Kába) őrizték</li>\r\n    </ul>\r\n  </li>\r\n  <li>Mohamed (570-632):\r\n    <ul>\r\n      <li>Vallási tanaihoz zsidó, keresztény és keleti tanításokat használt</li>\r\n      <li>Isten (Allah) Gábriel arkangyal útján nyilatkoztatta ki igazságait</li>\r\n      <li>Végítélet, egyetlen Isten (Allah) hatalma</li>\r\n      <li>Iszlám = teljes meghódolás, engedelmesség</li>\r\n      <li>622-ben Mekkából Medinába kergették (hidzsra) – a mohamedán időszámítás kezdete</li>\r\n    </ul>\r\n  </li>\r\n</ul>\r\n\r\n<h2>Az iszlám vallás fő tanításai</h2>\r\n<ul>\r\n  <li>Allah az isten, Mohamed a prófétája</li>\r\n  <li>Napi öt ima Mekka irányába</li>\r\n  <li>Alamizsnaosztás a szegényeknek</li>\r\n  <li>Ramadán havában böjt (Napkeltétől Napnyugtáig)</li>\r\n  <li>Mekkai zarándoklat</li>\r\n  <li>Dzsihád (Szent háború)</li>\r\n  <li>Kiegészítések:\r\n    <ul>\r\n      <li>maximum 4 feleség</li>\r\n      <li>tilalmak (pl. alkohol és disznóhús fogyasztása tilos)</li>\r\n    </ul>\r\n  </li>\r\n</ul>\r\n\r\n<h2>Az iszlám terjedése</h2>\r\n<ul>\r\n  <li>7-8. század: arabok elfoglalták Afrikát, Hispániát, Közel-Keletet, eljutottak Indiáig\r\n    <ul>\r\n      <li>kezükbe kerültek a kereskedelmi utak</li>\r\n      <li>megőrizték és továbbadták a hellenisztikus műveltséget</li>\r\n      <li>meggyengült a Bizánci Birodalom</li>\r\n    </ul>\r\n  </li>\r\n  <li>Előretörésüket Európában 732 Poitiers-nál (Martell Károly), 740 Bizánciak (görögtűz) állították meg</li>\r\n  <li>Iszlám kultúra:\r\n    <ul>\r\n      <li>türelmes és befogadó más kultúrákkal szemben</li>\r\n      <li>arab fordítások az ókori görög, római, zsidó és más keleti kultúrák alkotásaiból</li>\r\n      <li>tudományok fejlődése: csillagászat, kémia (alkímia, elixír), matematika (algebra)</li>\r\n      <li>megőrizte az antik műveltséget és közvetítette Európa felé</li>\r\n      <li>kereskedők bejárták a világot, feljegyzéseket készítettek</li>\r\n    </ul>\r\n  </li>\r\n</ul>', 'Egyetemestortenelem/korakozepkor.jpeg'),
(21, 'Érett középkor', 1, '<h2>A Nyugat-Római birodalom utódállamai</h2>\r\n\r\n<ul>\r\n  <li><strong>Keleti Gót Királyság:</strong> Nagy Theodorik vezetésével jött létre az 5. század végén Itáliában.</li>\r\n  <li><strong>Longobárd Királyság:</strong> a 6. század közepén longobárdok alapították Itália északi részén.</li>\r\n  <li><strong>Pápai Állam:</strong>\r\n    <ul>\r\n      <li>a Róma központú egyház függetlenítette magát a világi hatalomtól</li>\r\n      <li>756-ban jött létre, amikor Kis Pippin Róma és Ravenna vidékét a pápaságnak adományozta</li>\r\n    </ul>\r\n  </li>\r\n  <li><strong>Frank Királyság:</strong>\r\n    <ul>\r\n      <li>a germán frank törzsek az 5. században betelepültek Gallia területére</li>\r\n      <li>Klodvig felvette a katolikus kereszténységet és dinasztiát alapított (Meroving dinasztia)</li>\r\n    </ul>\r\n  </li>\r\n</ul>\r\n\r\n<h2>A Frank Birodalom</h2>\r\n\r\n<h3>A Karoling-dinasztia felemelkedése</h3>\r\n<ul>\r\n  <li><strong>Martell Károly</strong> majordomus (udvarnagy) 732-ben Poitiers-nál legyőzte az előrenyomuló arabokat.</li>\r\n  <li>Fia, <strong>Kis Pippin</strong> 751-ben a pápa segítségével királlyá koronáztatta magát (hálából létrehozta a Pápai Államot).</li>\r\n  <li>Kis Pippin fia, <strong>Nagy Károly</strong>:\r\n    <ul>\r\n      <li>hódításokat folytatott</li>\r\n      <li>erős államot szervezett</li>\r\n      <li>800-ban császárrá koronáztatta magát</li>\r\n    </ul>\r\n  </li>\r\n</ul>\r\n\r\n<h3>A frank állam</h3>\r\n<ul>\r\n  <li>Központja az Aacheni palota</li>\r\n  <li>A birodalom területét grófságokra és őrgrófságokra osztották:\r\n    <ul>\r\n      <li>élükön a grófok (comes) és őrgrófok álltak</li>\r\n      <li>feladatuk: adószedés, bíráskodás, hadvezetés</li>\r\n    </ul>\r\n  </li>\r\n  <li>Alkuin vezetésével egységesítették az írást (karoling minuscula):\r\n    <ul>\r\n      <li>az írásos ügyek intézését a kancellária végezte (oklevelek)</li>\r\n      <li>írott rendeletekkel irányították a birodalmat</li>\r\n    </ul>\r\n  </li>\r\n  <li>Nagy Károly halála után hatalmi harcok kezdődtek:\r\n    <ul>\r\n      <li>843-ban a verduni szerződésben unokái három részre osztották a birodalmat:\r\n        <ul>\r\n          <li>Nyugati frank királyság: Kopasz Károly birtoka (Franciaország)</li>\r\n          <li>Keleti frank királyság: Német Lajos birtoka (Németország)</li>\r\n          <li>Középső területek: Lothar birtoka (Itália, Burgundia, Lotharingia)</li>\r\n        </ul>\r\n      </li>\r\n      <li>A birodalom gyengeségét kihasználva a tartományok vezetői önállósodtak:\r\n        <ul>\r\n          <li>anarchia bontakozott ki</li>\r\n          <li>a normann (viking) és az arab támadások ellen sokáig képtelenek voltak védekezni</li>\r\n        </ul>\r\n      </li>\r\n    </ul>\r\n  </li>\r\n  <li>A külső támadások hatására erős központi hatalom jött létre:\r\n    <ul>\r\n      <li>Franciaország</li>\r\n      <li>Anglia</li>\r\n      <li>Német-Római Birodalom (I. Ottó hozta létre 962-ben)</li>\r\n    </ul>\r\n  </li>\r\n</ul>\r\n\r\n<h2>A Kelet-Római Birodalom</h2>\r\n<ul>\r\n  <li>A Keletrómai Birodalom a 6-10. század között a világ gazdasági, tudományos és művészeti központja volt:\r\n    <ul>\r\n      <li>Gazdasági fejlődés:\r\n        <ul>\r\n          <li>virágzó városokban nagyszámú kézműves réteg élt</li>\r\n          <li>fennmaradt a pénzgazdálkodás</li>\r\n          <li>fejlődött a kereskedelem</li>\r\n        </ul>\r\n      </li>\r\n      <li>Erős államhatalom:\r\n        <ul>\r\n          <li>központi hadsereg</li>\r\n          <li>adórend</li>\r\n        </ul>\r\n      </li>\r\n    </ul>\r\n  </li>\r\n  <li>6. században <strong>Justinianus császár</strong> (527-565):\r\n    <ul>\r\n      <li>Római jog gyűjteményes összefoglalása (Corpus Juris Civilis)</li>\r\n      <li>Hadjáratokat indított a nyugati területek visszahódításáért (Itália)</li>\r\n      <li>Felépítette a Hagia Sophia székesegyházat Konstantinápolyban</li>\r\n    </ul>\r\n  </li>\r\n  <li>8. században az arabok támadásai miatt területeket vesztett, majd a <strong>Makedón-dinasztia</strong> uralma alatt alakult ki a Bizánci Birodalom.</li>\r\n</ul>\r\n\r\n<h2>A szlávok</h2>\r\n<ul>\r\n  <li>Őshazájuk a Visztula - Dnyeper-folyók közötti terület (Pripjáty mocsarak)</li>\r\n  <li>6. században déli és nyugati irányba vándoroltak:\r\n    <ul>\r\n      <li>túlnépesedés</li>\r\n      <li>germán vándorlások</li>\r\n      <li>Bizánc meggyengülése</li>\r\n    </ul>\r\n  </li>\r\n  <li>Fejlődésük szétvált:\r\n    <ul>\r\n      <li>Nyugati szlávok: morvák, csehek, lengyelek</li>\r\n      <li>Déli szlávok: bolgárok, horvátok, szerbek</li>\r\n      <li>Keleti szlávok: oroszok, ukránok, fehér oroszok</li>\r\n    </ul>\r\n  </li>\r\n</ul>\r\n\r\n<h2>A keresztény egyház helyzete a kora középkorban</h2>\r\n<ul>\r\n  <li>Nyugaton a Róma püspökei (pápa) függetlenedtek a világi hatalomtól (756-ban létrejött a Pápai állam)</li>\r\n  <li>Keleten fennmaradt a császárok egyház feletti hatalma</li>\r\n  <li>Az államalapítással egy időben az új népek felvették a kereszténységet:\r\n    <ul>\r\n      <li>Nyugati: Katolikus (Róma központú, egyetemes)</li>\r\n      <li>Keleti: Ortodox / görögkeleti (bizánci) kereszténység</li>\r\n    </ul>\r\n  </li>\r\n  <li>A térítő munkát szerzetesi közösségek végezték (pl. bencések)</li>\r\n  <li>Nyugati és Keleti egyház közötti ellentétek 1054-ben egyházszakadáshoz (Szkizma) vezettek</li>\r\n</ul>\r\n\r\n<h2>Az iszlám vallás kialakulása</h2>\r\n<ul>\r\n  <li>Arab-félsziget, nomád arabok (beduinok)\r\n    <ul>\r\n      <li>Harcoltak a vízért, oázisokért és állatokért</li>\r\n      <li>Kereskedővárosok a tömjénút mentén, pl. Mekka, ahol a Fekete Követ (Kába) őrizték</li>\r\n    </ul>\r\n  </li>\r\n  <li>Mohamed (570-632):\r\n    <ul>\r\n      <li>Vallási tanaihoz zsidó, keresztény és keleti tanításokat használt</li>\r\n      <li>Isten (Allah) Gábriel arkangyal útján nyilatkoztatta ki igazságait</li>\r\n      <li>Végítélet, egyetlen Isten (Allah) hatalma</li>\r\n      <li>Iszlám = teljes meghódolás, engedelmesség</li>\r\n      <li>622-ben Mekkából Medinába kergették (hidzsra) – a mohamedán időszámítás kezdete</li>\r\n    </ul>\r\n  </li>\r\n</ul>\r\n\r\n<h2>Az iszlám vallás fő tanításai</h2>\r\n<ul>\r\n  <li>Allah az isten, Mohamed a prófétája</li>\r\n  <li>Napi öt ima Mekka irányába</li>\r\n  <li>Alamizsnaosztás a szegényeknek</li>\r\n  <li>Ramadán havában böjt (Napkeltétől Napnyugtáig)</li>\r\n  <li>Mekkai zarándoklat</li>\r\n  <li>Dzsihád (Szent háború)</li>\r\n  <li>Kiegészítések:\r\n    <ul>\r\n      <li>maximum 4 feleség</li>\r\n      <li>tilalmak (pl. alkohol és disznóhús fogyasztása tilos)</li>\r\n    </ul>\r\n  </li>\r\n</ul>\r\n\r\n<h2>Az iszlám terjedése</h2>\r\n<ul>\r\n  <li>7-8. század: arabok elfoglalták Afrikát, Hispániát, Közel-Keletet, eljutottak Indiáig\r\n    <ul>\r\n      <li>kezükbe kerültek a kereskedelmi utak</li>\r\n      <li>megőrizték és továbbadták a hellenisztikus műveltséget</li>\r\n      <li>meggyengült a Bizánci Birodalom</li>\r\n    </ul>\r\n  </li>\r\n  <li>Előretörésüket Európában 732 Poitiers-nál (Martell Károly), 740 Bizánciak (görögtűz) állították meg</li>\r\n  <li>Iszlám kultúra:\r\n    <ul>\r\n      <li>türelmes és befogadó más kultúrákkal szemben</li>\r\n      <li>arab fordítások az ókori görög, római, zsidó és más keleti kultúrák alkotásaiból</li>\r\n      <li>tudományok fejlődése: csillagászat, kémia (alkímia, elixír), matematika (algebra)</li>\r\n      <li>megőrizte az antik műveltséget és közvetítette Európa felé</li>\r\n      <li>kereskedők bejárták a világot, feljegyzéseket készítettek</li>\r\n    </ul>\r\n  </li>\r\n</ul>', 'Egyetemestortenelem/erettkozepkor.jpeg');
INSERT INTO `topics` (`id`, `title`, `category_id`, `content`, `img`) VALUES
(22, 'Kora újkor', 1, ' <h2>I. A nagy földrajzi felfedezések és következményei</h2>\r\n\r\n    <h3>Kiváltó okai:</h3>\r\n    <ul>\r\n        <li>Európában a 15. század elején jelentősen megnőtt a távol keleti luxuscikkek (fűszerek, selyem és porcelán) iránti igény. A megdrágult kereskedelem ellenértéke főként az arany lehetett, ezért kimerültek az európai nemesfém bányák (pl.: Magyarország), és aranyéhség keletkezett.</li>\r\n        <li>Ezzel együtt a török terjeszkedés elzárta az évszázados levantei kereskedelmi utakat, ezért drágult a behozott áruk értéke.</li>\r\n        <li>A nagy nyereség reményében portugál és spanyol hajósok új útvonalat kerestek India és Kína felé az Atlanti-óceán irányában.</li>\r\n    </ul>\r\n\r\n    <h3>A felfedezések előfeltételei:</h3>\r\n    <ul>\r\n        <li>Technikai-tudományos fejlődés ment végbe: új hajótípus jelent meg a caravella, elterjedt az iránytű, asztroláb, sextáns és a kormánylapát.</li>\r\n        <li>Tengerész Henrik (portugál) herceg hajózási iskolát hozott létre.</li>\r\n        <li>Előkerültek az ókori tudományos ismeretek, pl.: Ptolemaiosz Föld térképe (gömb alak), fejlődött a csillagászat, Toscanelli megrajzolta az Atlanti-óceán térképét.</li>\r\n    </ul>\r\n\r\n    <h3>A felfedezések menete:</h3>\r\n    <ul>\r\n        <li>1487-ben Bartolomeo Diaz elérte Afrika déli csúcsát (Jóreménység-foka).</li>\r\n        <li>1492-ben Kolumbusz Kristóf felfedezte Amerikát.</li>\r\n        <li>1499-1507 között Amerigo Vespucci feltérképezte Dél-Amerika keleti partvonalát (Újvilág).</li>\r\n        <li>1498-ban Afrika körül hajózásával Vasco da Gama eljutott Indiába.</li>\r\n        <li>1519-22 között Magellán expedíciója körbe hajózta a Földet.</li>\r\n    </ul>\r\n\r\n    <h3>A felfedezések következményei:</h3>\r\n    <ul>\r\n        <li>A közép és Dél-Amerikában talált birodalmakat (maja, azték, inka) elpusztították.</li>\r\n        <li>Az őslakosság nagy része a járványok és a nehéz munka hatására kihalt, ezért Afrikából négereket hurcoltak be Amerikába rabszolgának.</li>\r\n        <li>Új növényfajták jelentek meg Európában, pl.: kukorica, burgonya, paprika, paradicsom, napraforgó, dohány, kakaó, vanília, ananász.</li>\r\n        <li>Amerikában megkezdődött az ültetvényes gazdálkodás: gyapot, cukornád, dohány.</li>\r\n        <li>A portugálok és a spanyolok gyarmatbirodalmat hoztak létre az Újvilágban (Eldorádó=„az ígéret földje”).</li>\r\n    </ul>\r\n\r\n    <h3>A felfedezések gazdasági következményei:</h3>\r\n    <ul>\r\n        <li>Az Újvilág nemesfémbányáiból nagy mennyiségű nemesfém áramlott Európába, ezért „árrobbanás” ment végbe → nőtt a pénz mennyisége és csökkent az értéke → megnőttek az árak → infláció keletkezett.</li>\r\n        <li>Nyugat-Európa a felfedezések hatására centrális helyzetbe került, ezért a gabonatermelés csökkent, a juhtenyésztés és az ipari termelés került előtérbe, mert árucikkei jól eladhatók voltak aranyért.</li>\r\n        <li>Kelet-Európa a nyugati élelmiszerigény miatt a mezőgazdasági termelésre helyezte a hangsúlyt, ezért kialakult a második jobbágyság.</li>\r\n        <li>A folyamat hatására Európa gazdaságilag kettészakadt. Nyugaton az Atlanti–óceán térségében fellendült az ipar és a kereskedelem, háttérbe szorult a mezőgazdaság, közép és kelet-Európában fellendült az élelmiszertermelés a Nyugat számára.</li>\r\n        <li>A gyors ipari fejlődés hatására létrejöttek a manufaktúrák, kiépült a hitelszervezet és a bankhálózat. Kialakult a világpiac (globalizáció).</li>\r\n        <li>A korszak végén megjelent a vetésforgó és a belterjes, istállózó állattenyésztés, ezért kevés ember sok élelmiszert tudott termelni kis területen, ami Kelet-Európa számára kedvezőtlen hatással járt.</li>\r\n        <li>A fellendülő ipari termelés hatására intenzív városiasodás zajlott Nyugat-Európában.</li>\r\n        <li>A reformáció polgári irányzata, a kálvinizmus elősegítette a polgári mentalitás elterjedését (pl.: predestináció tana). Az ismeretek gyors áramlását a könyvnyomtatás biztosította.</li>\r\n        <li>Az öntudatosodás a polgári forradalmak sorozatához vezetett, pl.: németalföldi szabadságharc, angol polgári forradalom.</li>\r\n        <li>A katolicizmus visszaszorult, a tekintélyelv helyét a kritikus gondolkodás vette át, pl.: Kopernikusz, Galilei, Newton felfedezései.</li>\r\n    </ul>\r\n\r\n    <h2>II. A reformáció és fő irányzatai</h2>\r\n\r\n    <h3>A reformáció kialakulásának okai:</h3>\r\n    <ul>\r\n        <li>A 15. században a katolikus egyház ismét súlyos válságba került. Okai:\r\n            <ul>\r\n                <li>A papság fényűző élete s a reneszánsz pápák világias és züllött életmódja.</li>\r\n                <li>Búcsúcédulák árusítása: X. Leó pápa a Szent Péter Székesegyház építési költségeit búcsúcédulákból kívánta fedezni. A búcsúcédula megvásárlásával felmentést lehetett nyerni a bocsánatos bűnök vagy a vezeklés alól, ezért általános elégedetlenség és felháborodás bontakozott ki a hívek körében.</li>\r\n                <li>A reneszánsz és a humanizmus eszmerendszere, a felfedezések eredményei és a természettudományok fejlődése szétrombolta a hagyományos középkori világképet.</li>\r\n            </ul>\r\n        </li>\r\n        <li>A felfedezések hatására az európai kereskedelem központja az Atlanti-óceán partvidékére helyeződött át, ezért elsorvadtak a hagyományos középkori kereskedő utak.</li>\r\n        <li>A német kereskedővárosok elszegényedtek, és a széttagolt birodalomban a fejedelmek a gazdag német egyház földjeinek megszerzésére törekedtek (összes földek 1/3-a).</li>\r\n    </ul>\r\n\r\n    <h3>A reformáció fő irányzatai:</h3>\r\n\r\n    <h4>1. A fejedelmi irányzat (evangélikusok vagy lutheránusok):</h4>\r\n    <ul>\r\n        <li>Luther Márton Szent Ágoston rendi szerzetes (egyetemi tanár) római útján megbizonyosodott a pápaság romlottságáról, a búcsúcédulák árusításának igazi okairól. Összefoglalta kifogásait a katolikus egyházzal szemben, és 1517. október 31-én kifüggesztette vitairatát a wittenbergi vártemplom kapujára. Luther tanainak (95 tétel) alapja a Biblia:\r\n            <ul>\r\n                <li>\"a bűnt egyedül Isten bocsáthatja meg\" – Az ember egyedül Isten kegyelméből, a hit által nyerheti el bűnei bocsánatát.</li>\r\n                <li>\"egyedül a hit által üdvözülhet az ember\" – ezért nincs szükség egyházi közvetítésre, pl.: pápa.</li>\r\n                <li>Az egyházi birtokok kiárusítása (szekularizáció).</li>\r\n                <li>A gyónás, a cölibátus és a szerzetesség eltörlése.</li>\r\n                <li>Bevezette az anyanyelvű igehirdetést, ezért lefordította a Bibliát német nyelvre. Követői az evangélium szó után az evangelista nevet kapták.</li>\r\n            </ul>\r\n        </li>\r\n        <li>Luther fellépésének következményei:\r\n            <ul>\r\n                <li>A pápa kiátkozta Luthert, ezért V. Károly császár eretnekké nyilvánította.</li>\r\n                <li>Luther elégette az őt kiátkozó pápai bullát.</li>\r\n                <li>A német fejedelmek Luther mellé álltak. Céljuk a katolikus egyház földjeinek megszerzése volt hatalmuk növelése érdekében.</li>\r\n                <li>1529-ben a speyeri birodalmi gyűlés döntése értelmében Luther követői megmaradhattak hitükön, de nem terjeszthették azt (protestánsok), ezért a Schmalkaldeni szövetség (protestáns fejedelmek) és a császár közt kitört a német vallásháború, melyet az augsburgi vallásbéke zárt le 1555-ben („Akié a föld, azé a vallás”).</li>\r\n                <li>V. Károly uralma megingott (politikai és vallási megosztottság), és 1556-ban lemondott a spanyol trónról fia II. Fülöp javára.</li>\r\n                <li>Az evangélikus egyház elterjedése: német területek, Skandinávia, Ausztria, Csehország, Magyarország.</li>\r\n            </ul>\r\n        </li>\r\n    </ul>\r\n\r\n    <h4>2. A népi irányzatok:</h4>\r\n    <ul>\r\n        <li>Münzer Tamás zwickaui prédikátor tanításainak hatására bontakoztak ki:\r\n            <ul>\r\n                <li>Csecsemőkeresztelés elvetése.</li>\r\n                <li>A jézusi (evangéliumi) szegénység hirdetése.</li>\r\n                <li>A magántulajdon elvetése, a Bibliát szó szerint értelmezik.</li>\r\n            </ul>\r\n        </li>\r\n        <li>Hatására 1524-25 között zajlott a német parasztháború (Dél-Közép Németország), melyben Münzert és követőit megölték. Maradék híveik elmenekültek, pl. Magyarországra.</li>\r\n        <li>Irányzatai:\r\n            <ul>\r\n                <li>Antitrinitáriusok (= szentháromság tagadók) elvetették Jézus Krisztus istenségét, az eredendő bűnt és a predesztinációt. Vezetőjüket Servét Mihályt Kálvin János kivégeztette.</li>\r\n                <li>Anabaptisták (újrakeresztelők): a gyermekkeresztség ellen tiltakoztak - csak akkor kell keresztelni, amikor a gyermek erre már megérett.</li>\r\n            </ul>\r\n        </li>\r\n    </ul>\r\n\r\n    <h4>3. A polgári irányzat (reformátusok vagy kálvinisták):</h4>\r\n    <ul>\r\n        <li>Vezetője Kálvin János genfi prédikátor volt. Tanításai:\r\n            <ul>\r\n                <li>Predesztináció = eleve elrendeltetés tana: Isten az emberek sorsát születésüktől fogva meghatározza.</li>\r\n                <li>Puritánság = egyszerű egyházi szertartások.</li>\r\n                <li>Az ember szorgalmas tevékenységével teljesíti Isten akaratát (világi aszkézis: szerény, mértéktartó, szorgalmas élet).</li>\r\n                <li>Zsarnokölési elmélete: a polgárok megölhetik a zsarnokokat.</li>\r\n                <li>Pénzfelhalmozás jogossága, bármit lehet szabadon vásárolni (kamatszedés engedélyezése).</li>\r\n                <li>Demokratikus egyházszervezet: alapvető intézmény a presbitérium (presbitérium = világi jellegű tanács) felállítása.</li>\r\n                <li>Az egyház irányelveket fogalmaz meg a polgárok számára.</li>\r\n            </ul>\r\n        </li>\r\n        <li>A kálvinizmus (református hit) elterjedése: Svájc, Franciaország, Németalföld, Skócia, Magyarország.</li>\r\n    </ul>\r\n    <h2>III. Az abszolutizmus kora</h2>\r\n\r\n    <h3>1. A spanyol abszolutizmus kialakulása:</h3>\r\n    <ul>\r\n        <li>Spanyolország 1479-ben jött létre Kasztília és Aragónia egyesülésével.</li>\r\n        <li>1492-ben kiűzték az arabokat a félsziget déli részéről.</li>\r\n        <li>Amerika felfedezése után nagy mennyiségű nemesfém áramlott az országba, ezért Spanyolország nagyhatalommá vált.</li>\r\n        <li>Habsburg Szép Fülöp herceg és Őrült Johanna házasságával a spanyol trón a Habsburgok kezébe került.</li>\r\n        <li>I. Károly (1516-1556) 1519-ben megszerezte a Német-Római császári címet (V. Károly). Célja: a császári hatalom tekintélyének visszaállítása volt, ezért:\r\n            <ul>\r\n                <li>Zsoldoshadsereget hozott létre.</li>\r\n                <li>Flottaépítés (Nagy Armada).</li>\r\n                <li>Visszaszorította a tartományi rendeket.</li>\r\n                <li>Központosított hivatalrendszert épített ki (uralkodó feltétlen hatalma).</li>\r\n                <li>Megerősítette a katolikus egyház hatalmát (ellenreformáció elindítása – Tridenti zsinat).</li>\r\n            </ul>\r\n        </li>\r\n        <li>II. Fülöp (1556-1598) célja: katolikus világhatalom létrehozása volt, ezért:\r\n            <ul>\r\n                <li>Kiépítette az abszolút királyi hatalmat.</li>\r\n                <li>1571-ben szövetségeseivel (pl.: Velence) Lepantónál megállította az oszmánok előrenyomulását (török flotta pusztulása).</li>\r\n            </ul>\r\n        </li>\r\n        <li>De:\r\n            <ul>\r\n                <li>1588-ban a spanyol “Nagy Armada” vereséget szenvedett az angol flottától.</li>\r\n                <li>Hollandia kialakulásával elveszítette Németalföld északi részét.</li>\r\n            </ul>\r\n        </li>\r\n    </ul>\r\n\r\n    <h3>2. Az angol abszolutizmus létrejötte:</h3>\r\n    <ul>\r\n        <li>A rózsák háborúja után VII. (Tudor) Henrik (1485-1509) szerezte meg a trónt. Célja: erős királyi hatalom megteremtése volt, ezért:\r\n            <ul>\r\n                <li>Létrehozta a Titkos Tanácsot.</li>\r\n                <li>Zsoldos hadsereget állított fel.</li>\r\n                <li>Megerősítette a központi hatalmat.</li>\r\n            </ul>\r\n        </li>\r\n        <li>VIII. Henrik (1509-1547):\r\n            <ul>\r\n                <li>Egyeduralkodóként kormányzott.</li>\r\n                <li>Elszakította az angol egyházat Rómától (anglikán egyház kiépítése - 1534).</li>\r\n            </ul>\r\n        </li>\r\n        <li>I. Erzsébet (1558-1603):\r\n            <ul>\r\n                <li>Támogatta a tengeri kereskedelmet (monopóliumok).</li>\r\n                <li>Anglia nagyhatalommá vált (1588 Nagy Armada legyőzése).</li>\r\n                <li>Uralkodása az angol abszolutizmus tetőfokát jelentette.</li>\r\n            </ul>\r\n        </li>\r\n        <li>I. Jakab és I. Károly uralkodása (1603-49):\r\n            <ul>\r\n                <li>Céljuk: a teljes abszolutizmus kiépítése volt, ezért:\r\n                    <ul>\r\n                        <li>Felújították a királyi regálékat.</li>\r\n                        <li>Adóemelést hajtottak végre.</li>\r\n                        <li>Növelték a katolikus egyház szerepét.</li>\r\n                    </ul>\r\n                </li>\r\n                <li>Következményei: puritánok (a kálvinizmus angol képviselői) és a parlament képviselői ellenálltak a királynak.</li>\r\n                <li>Skóciában felkelés kezdődött 1638-ban, ezért a királynak (I. Károly) pénzre volt szüksége és összehívta a parlamentet 1640-ben.</li>\r\n                <li>De: a király és a Parlament ellentéte miatt kitört a forradalom.</li>\r\n            </ul>\r\n        </li>\r\n    </ul>\r\n\r\n    <h3>Az angol polgári forradalom szakaszai:</h3>\r\n\r\n    <ul>\r\n        <li><strong>A polgárháború kora (1642-49):</strong>\r\n            <ul>\r\n                <li>I. Károly (1625-49) erőszakhoz folyamodott a Parlamenttel szemben.</li>\r\n                <li>A radikális puritánok hadsereget szerveztek Oliver Cromwell vezetésével (vasbordájúak hadserege) és legyőzték a királyt (1648).</li>\r\n                <li>Következményei: 1649-ben kivégezték a királyt, Anglia köztársasággá vált.</li>\r\n            </ul>\r\n        </li>\r\n\r\n        <li><strong>A Köztársaság kora (1649-60):</strong>\r\n            <ul>\r\n                <li>Cromwell katonai diktatúrát hozott létre. Intézkedései:\r\n                    <ul>\r\n                        <li>1651-ben bevezette a hajózási törvényt (csak angol hajók szállíthattak, ezért ellentétbe került Hollandiával).</li>\r\n                        <li>Hatására Anglia lett a tengerek ura.</li>\r\n                        <li>Elfoglalta Skóciát és Írországot: létrejött Nagy-Britannia.</li>\r\n                        <li>Cromwell halála után a tőkés vállalkozók visszahívták a Stuart királyokat.</li>\r\n                    </ul>\r\n                </li>\r\n            </ul>\r\n        </li>\r\n\r\n        <li><strong>A Stuart restauráció (1660-1688):</strong>\r\n            <ul>\r\n                <li>II. Károly és II. Jakab vissza akarták állítani az abszolutizmust, ezért meghívták a trónra a holland protestáns fejedelmet III. Orániai Vilmost (1688-1702).</li>\r\n            </ul>\r\n        </li>\r\n\r\n        <li><strong>A dicsőséges forradalom 1688-89:</strong>\r\n            <ul>\r\n                <li>Jognyilatkozat – polgári szabadságjogok biztosítása.</li>\r\n                <li>Államforma: alkotmányos monarchia „a király uralkodik, de nem kormányoz”.</li>\r\n                <li>Alapját az 1689-ben kiadott Jogok Nyilatkozata (Bill of Rights) szolgáltatta, tartalma:\r\n                    <ul>\r\n                        <li>A törvényhozó testület a parlament.</li>\r\n                        <li>A végrehajtó hatalom a parlamentnek felelős kormány.</li>\r\n                        <li>Független bíróságok létrehozása.</li>\r\n                        <li>A parlamentnek évente üléseznie kell.</li>\r\n                        <li>A király uralkodik, de nem kormányoz.</li>\r\n                        <li>A parlament beleszólhatott az adószedésbe és a hadsereg fenntartásába.</li>\r\n                    </ul>\r\n                </li>\r\n            </ul>\r\n        </li>\r\n    </ul>\r\n\r\n    <h3>3. A Francia abszolutizmus:</h3>\r\n    <ul>\r\n        <li>Franciaországban a 16. század első felében, I. Ferenc (1515-1547) uralkodása idején erősödött meg a királyi hatalom, aki Habsburgok megnövekedett európai hatalma miatt szövetségeseket keresett (Cognac-i Liga).</li>\r\n        <li>Halála után trónharcok kezdődtek, melyek vallási ellentétek formájában bontakoztak ki. Okai:\r\n            <ul>\r\n                <li>Elterjedt a kálvini reformáció Dél-Franciaországban: hugenották = francia protestánsok (főleg városi lakosok és parasztok).</li>\r\n                <li>A katolikusok és a hugenották között vallási, politikai ellentétek alakultak ki.</li>\r\n            </ul>\r\n        </li>\r\n        <li>Következménye:\r\n            <ul>\r\n                <li>1572-ben Párizsban Szt. Bertalan éjszakáján 3000 hugenottát mészároltak le a katolikusok (Bourbon-Valois esküvő), ezért vallási és polgárháború zajlott 1572-1589 között.</li>\r\n                <li>A küzdelem IV. (Bourbon) Henrik (1589-1610) királlyá koronázásával ért véget „Párizs megér egy misét”. Célja a belső béke megteremtése volt, ezért:\r\n                    <ul>\r\n                        <li>1598-ban kiadta a nantes-i ediktumot, ami biztosította a szabad vallásgyakorlást.</li>\r\n                        <li>Csökkentette a parasztok adóterheit.</li>\r\n                        <li>Fejlesztette a gazdaságot királyi manufaktúrák létrehozásával (luxus ipar).</li>\r\n                        <li>Támogatta a gyarmatosítást és a kereskedelmet.</li>\r\n                    </ul>\r\n                </li>\r\n                <li>XIII. Lajos (1610-1643) államminisztere Richelieu bíboros építette ki az abszolutizmus rendszerét:\r\n                    <ul>\r\n                        <li>Kiűzte a hugenottákat Franciaországból.</li>\r\n                        <li>1614 után nem hívta össze a rendi gyűlést, ezért a király rendeletekkel kormányoz.</li>\r\n                        <li>Királytól függő hivatalnokszervezetet és zsoldos haderőt szervezett.</li>\r\n                    </ul>\r\n                </li>\r\n                <li>XIV. Lajos (1643-1715) a „napkirály” uralkodása idején Franciaország Európa vezető nagyhatalma lett. Alapját a merkantilista gazdaságpolitika képezte:\r\n                    <ul>\r\n                        <li>Colbert pénzügyminiszter alakította ki.</li>\r\n                        <li>Cél: vámok segítségével megvédeni a belső ipart és exportálni a termékeket külföldre, hogy pénzt kapjanak érte.</li>\r\n                        <li>Manufaktúrákat hoztak létre, megszabják a minőséget és segítik a kereskedelmet.</li>\r\n                    </ul>\r\n                </li>\r\n                <li>De: a spanyol örökösödési háború (1701-1714) idején Franciaország súlyos politikai és gazdasági válságba került.</li>\r\n            </ul>\r\n        </li>\r\n    </ul>\r\n    <h3>4. A Dunai Habsburg Birodalom</h3>\r\n    <ul>\r\n        <li>A Habsburgok osztrák birodalmai I. Ferdinánd és utódai uralma alá kerültek:\r\n            <ul>\r\n                <li>Magyarországon csak megállítani tudták a török terjeszkedést.</li>\r\n                <li>A rendek és a központi hatalom viszonya vallási színezetet kapott:\r\n                    <ul>\r\n                        <li>Az osztrák tartományokban sikerült betiltatni a protestantizmust.</li>\r\n                        <li>Magyarországon és Csehországban a rendek ellenálltak (pl.: Bocskai felkelés).</li>\r\n                    </ul>\r\n                </li>\r\n            </ul>\r\n        </li>\r\n        <li>A cseh nemesség ellenállása miatt robbant ki a Harminc éves háború 1618-48 között (katolikus Liga – protestáns Unió küzdelme):\r\n            <ul>\r\n                <li>A háború első szakaszában (cseh szakasz) a cseh nemesség vereséget szenvedett (Fehér-hegyi csata), ezért:\r\n                    <ul>\r\n                        <li>Felszámolták a cseh rendi jogokat.</li>\r\n                        <li>A cseh nemesség birtokait németeknek adták.</li>\r\n                        <li>Csehország örökös tartománnyá vált.</li>\r\n                    </ul>\r\n                </li>\r\n                <li>A háború második és harmadik szakaszában (dán és svéd szakasz) váltakozó fölényű küzdelem zajlott a dán és a svéd uralkodók részvételével.</li>\r\n                <li>A negyedik, befejező szakaszban Franciaország a protestánsok mellé állt, így a Habsburgok békére kényszerültek.</li>\r\n            </ul>\r\n        </li>\r\n        <li>A háborút lezáró Vesztfáliai békét 1648-ban kötötték meg:\r\n            <ul>\r\n                <li>A Német-Római Birodalom több száz független állam halmaza maradt.</li>\r\n                <li>A birodalmi gyűlés döntésképtelenné vált.</li>\r\n                <li>A Habsburg dinasztia nem szenvedett teljes vereséget; az osztrák és cseh tartományokban felszámolta a rendiséget.</li>\r\n                <li>Franciaország Európa vezető hatalmává vált.</li>\r\n                <li>A porosz uralkodók megszerezték Brandenburgot.</li>\r\n            </ul>\r\n        </li>\r\n    </ul>\r\n\r\n    <h3>5. Közép- és Kelet-Európa a 16-17. században</h3>\r\n    <ul>\r\n        <li>A centrumtól keletre a kontinentális munkamegosztásnak köszönhetően Közép-Kelet-Európa áttért az élelmiszertermelésre:\r\n            <ul>\r\n                <li>Nyersanyagszállító és élelmiszertermelő szerep.</li>\r\n            </ul>\r\n        </li>\r\n        <li>A mezőgazdasági terményeket nagy haszonnal lehetett értékesíteni, ezért a nagybirtokosok:\r\n            <ul>\r\n                <li>Terményjáradékot követeltek a jobbágyoktól.</li>\r\n                <li>Kiterjesztették a majorságokat.</li>\r\n                <li>Növelték a robotmunka alkalmazását.</li>\r\n            </ul>\r\n        </li>\r\n        <li>Következménye:\r\n            <ul>\r\n                <li>Az Elbától keletre röghöz kötötték a jobbágyokat (második jobbágyság).</li>\r\n                <li>A nemesek megnövelték majorságukat, de a pénzt felélték.</li>\r\n                <li>Megfosztották a jobbágyokat a szabad költözés jogától.</li>\r\n            </ul>\r\n        </li>\r\n    </ul>\r\n\r\n    <h3>Lengyelország hanyatlása</h3>\r\n    <ul>\r\n        <li>A lengyel feudális viszonyokra is jellemző az örökös jobbágyság kialakulása, melynek hatására a lengyel nemesség jelentősen meggazdagodott és pozíciói megerősödtek.</li>\r\n        <li>A 16-17. századi Lengyelország Közép-Európa meghatározó hatalma volt:\r\n            <ul>\r\n                <li>1572-ben kihalt a Jagelló-ház.</li>\r\n                <li>III. Henrik 1573-ban megerősítette a lengyel nemesség jogait (Henrik-cikkelyek):\r\n                    <ul>\r\n                        <li>A Szejm csak olyan törvényt fogadhatott el, amely ellen az országgyűlés egyetlen tagja sem tiltakozott, ezzel működésképtelenné téve a törvényhozást.</li>\r\n                        <li>Létrehozta a lengyel nemesi köztársaságot.</li>\r\n                    </ul>\r\n                </li>\r\n                <li>1576-1586 között Báthory István erdélyi fejedelem lengyel királyként átmenetileg stabilizálta a helyzetet.</li>\r\n                <li>Lengyelországot a 18. században (1772, 1792, 1796) felosztották Poroszország, a Habsburg Birodalom és Oroszország között, s 1920-ig elvesztette önállóságát.</li>\r\n            </ul>\r\n        </li>\r\n    </ul>\r\n\r\n    <h3>Oroszország nagyhatalommá válása</h3>\r\n    <ul>\r\n        <li>IV. Iván (1533-1584) megerősítette a központi hatalmat:\r\n            <ul>\r\n                <li>Fellépett az ősi nemesi birtokosok ellen.</li>\r\n                <li>Felvette a császári = cári címet.</li>\r\n                <li>Megszerzte a Volga medencéjét.</li>\r\n            </ul>\r\n        </li>\r\n        <li>1613-ban Romanov-dinasztia került hatalomra.</li>\r\n        <li>I. (Nagy) Péter átvette a nyugat-európai mintákat:\r\n            <ul>\r\n                <li>Támogatta a manufaktúrákat.</li>\r\n                <li>Erős flottát és korszerű hadsereget épített.</li>\r\n                <li>Megalapította Szentpétervárt (1703).</li>\r\n            </ul>\r\n        </li>\r\n    </ul>\r\n\r\n    <h3>Az Oszmán Birodalom fénykora és hanyatlása</h3>\r\n    <ul>\r\n        <li>A 16. századra jelentősen megerősödött. Fénykorát I. (Törvényhozó) Szulejmán (1520-1566) idején élte:\r\n            <ul>\r\n                <li>Meghódította Magyarország középső részét.</li>\r\n                <li>Folyamatos harcban állt a perzsákkal.</li>\r\n            </ul>\r\n        </li>\r\n        <li>A 16. század végétől megállt a terjeszkedése, ezért meggyengült:\r\n            <ul>\r\n                <li>A Habsburgok a XVII. század végén felszabadították Magyarországot.</li>\r\n                <li>Az Oszmán Birodalom elvesztette nagyhatalmi szerepét.</li>\r\n            </ul>\r\n        </li>\r\n    </ul>\r\n\r\n    <h3>6. Művelődés és életmód a kora újkorban</h3>\r\n    <ul>\r\n        <li>A természettudományos fejlődés hatással volt a világkép megváltozására:\r\n            <ul>\r\n                <li>Csillagászati felfedezések:\r\n                    <ul>\r\n                        <li>Kopernikusz (lengyel csillagász): a Nap a világegyetem központja = heliocentrikus világkép (szemben a geocentrikus világképpel).</li>\r\n                        <li>Galileo Galilei bizonyította Kopernikusz állítását (szabadesés, ingamozgás, bolygók mozgása) – „És mégis mozog a Föld!”</li>\r\n                        <li>Isaac Newton megalkotta az általános tömegvonzás és a mechanika törvényeit.</li>\r\n                    </ul>\r\n                </li>\r\n            </ul>\r\n        </li>\r\n        <li>A változások hatására átalakult a társadalom és államkép:\r\n            <ul>\r\n                <li>Machiavelli a fejedelmi hatalom mindenhatóságát hirdette: „A cél szentesíti az eszközt”.</li>\r\n                <li>Az ideális állam és társadalom megálmodói (utópisták):\r\n                    <ul>\r\n                        <li>John Locke: az alkotmányos monarchiát állította példának.</li>\r\n                        <li>Morus Tamás: Seholnincs ország.</li>\r\n                        <li>Campanella: Napállam.</li>\r\n                        <li>Francis Bacon: Új Atlantisz.</li>\r\n                    </ul>\r\n                </li>\r\n            </ul>\r\n        </li>\r\n        <li>Új jelenségek a kora újkorban:\r\n            <ul>\r\n                <li>A jogi különbségek helyébe vagyoniak léptek.</li>\r\n                <li>Növekedni kezdtek a városok.</li>\r\n                <li>Terjedtek a könyvek, újságok, kávéházak.</li>\r\n                <li>Ritkán tisztálkodtak – éhínségek (kis jégkorszak), járványok pusztítottak.</li>\r\n            </ul>\r\n        </li>\r\n    </ul>', 'Egyetemestortenelem/koraujkor.jpeg');

